- @Injectable class NotificationsService
- private readonly logger = new Logger(NotificationsService.name)
- private readonly sesClient: SESClient
- private readonly fromEmail: string

- constructor(
    configService: ConfigService,
    @InjectModel('Patient') patientModel,
    @InjectModel('User') userModel,
    professionalsService: ProfessionalsService,
  )
  - const sesConfig = configService.get('ses')
  - this.sesClient = new SESClient({
      region: sesConfig.region,
      credentials: sesConfig.accessKeyId ? { accessKeyId, secretAccessKey: sesConfig.secretAccessKey } : undefined,
    })
    // Note: if accessKeyId is undefined, SES uses the default IAM role chain (EC2 instance profile in production)
  - this.fromEmail = sesConfig.fromEmail

- private async sendEmail(to: string, subject: string, htmlBody: string, textBody: string): Promise<void>
  - try {
      const command = new SendEmailCommand({
        Source: this.fromEmail,
        Destination: { ToAddresses: [to] },
        Message: {
          Subject: { Data: subject, Charset: 'UTF-8' },
          Body: {
            Html: { Data: htmlBody, Charset: 'UTF-8' },
            Text: { Data: textBody, Charset: 'UTF-8' },
          },
        },
      });
      await this.sesClient.send(command);
    } catch (err) {
      this.logger.warn(`Failed to send email to ${to}: ${err.message}`);
      // Do NOT rethrow — notifications are best-effort
    }

- async notifyAppointmentCreated(appointment: AppointmentDocument): Promise<void>
  - Resolve patient and professional emails by querying respective models
  - patient: find Patient by userId, then User by patient.userId to get email; OR find User directly by patientId (depending on how appointment.patientId is stored)
  - professional: find Professional by id, then User by professional.userId to get email
  - patientName: from Patient document; professionalName: from Professional or its User displayName
  - Render template for patient with recipientType='patient' → sendEmail to patient email
  - Render template for professional with recipientType='professional' → sendEmail to professional email

- async notifyAppointmentConfirmed(appointment: AppointmentDocument): Promise<void>
  - Resolve patient email and names
  - Render appointmentConfirmedTemplate → sendEmail to patient email only

- async notifyAppointmentCancelled(appointment: AppointmentDocument, cancelledBy: 'patient' | 'provider'): Promise<void>
  - Resolve both names
  - If cancelledBy === 'patient': send to professional with otherPartyName=patientName
  - If cancelledBy === 'provider': send to patient with otherPartyName=professionalName

